mapper.insert:
        DROP
        SEQUENCE IF EXISTS fr_ai_annotation_${sequenceNumber}_annotation_id_seq;
	    CREATE
        SEQUENCE fr_ai_annotation_${sequenceNumber}_annotation_id_seq START
        1;

mapper.select:
SELECT sum(ST_Area(contour40000)) AS area
from fr_ai_annotation_${sequenceNumber}
where single_slide_id = #{singleSlideId}
  and category_id = #{categoryId}

mapper.insert:
CREATE TABLE "public".fr_ai_annotation_${sequenceNumber}
(
    "annotation_id"   int8 NOT NULL DEFAULT nextval('fr_ai_annotation_${sequenceNumber}_annotation_id_seq'::regclass),
    "area"            VARCHAR(50) COLLATE "pg_catalog"."default",
    "perimeter"       VARCHAR(50) COLLATE "pg_catalog"."default",
    "description"     VARCHAR(100) COLLATE "pg_catalog"."default",
    "category_id"     INT8,
    "contour625"      geometry ( GEOMETRY ),
    "contour2500"     geometry ( GEOMETRY ),
    "contour10000"    geometry ( GEOMETRY ),
    "contour40000"    geometry ( GEOMETRY ),
    "location_type"   VARCHAR(100) COLLATE "pg_catalog"."default",
    "annotation_type" VARCHAR(50) COLLATE "pg_catalog"."default",
    "create_by"       INT8,
    "create_time"     DATE,
    "update_by"       INT8,
    "update_time"     DATE,
    "slide_id"        INT8,
    "single_slide_id" INT8,
    "single"          INT2          DEFAULT 1,
    "contour_type"    INT8          DEFAULT 4,
    "id"              VARCHAR(500) COLLATE "pg_catalog"."default",
    CONSTRAINT "fr_ai_annotation_${sequenceNumber}_pkey" PRIMARY KEY ("annotation_id")
);


ALTER TABLE "fr_ai_annotation_${sequenceNumber}" OWNER TO "postgres";


CREATE INDEX "fr_ai_annotation_${sequenceNumber}_slide_id_idx" ON "public"."fr_ai_annotation_${sequenceNumber}" USING btree (
    "single_slide_id" "pg_catalog"."int8_ops" ASC NULLS LAST
    );

CREATE INDEX "fr_ai_annotation_${sequenceNumber}_contour40000_idx" ON "public"."fr_ai_annotation_${sequenceNumber}" USING gist (
    "contour40000" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_ai_annotation_${sequenceNumber}_contour625_idx" ON "public"."fr_ai_annotation_${sequenceNumber}" USING gist (
    "contour625" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_ai_annotation_${sequenceNumber}_contour2500_idx" ON "public"."fr_ai_annotation_${sequenceNumber}" USING gist (
    "contour2500" "public"."gist_geometry_ops_2d"
    );

CREATE INDEX "fr_ai_annotation_${sequenceNumber}_contour10000_idx" ON "public"."fr_ai_annotation_${sequenceNumber}" USING gist (
    "contour10000" "public"."gist_geometry_ops_2d"
    );

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."annotation_id" IS '主键id';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."area" IS '面积';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."perimeter" IS '周长';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."description" IS '轮廓描述';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."category_id" IS '轮廓标签id';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."contour40000" IS '轮廓坐标';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."contour625" IS '轮廓坐标625';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."contour2500" IS '轮廓坐标2500';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."contour10000" IS '轮廓坐标10000';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."location_type" IS '轮廓类型';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."annotation_type" IS '标注类型(AI表示AI算出的标注，Draw表示前端绘制的标注)';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."create_by" IS '标注创建者';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."create_time" IS '创建时间';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."update_by" IS '更新者';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."update_time" IS '更新时间';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."slide_id" IS '切片id';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."single_slide_id" IS '单切片id';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."single" IS '单切片id标识';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."contour_type" IS '轮廓类型标识';

COMMENT ON COLUMN "public"."fr_ai_annotation_${sequenceNumber}"."id" IS 'geojson中数据id';

mapper.select:
select annotation_id, area, perimeter, description, category_id, location_type, annotation_type, create_by, create_time, update_by, update_time, slide_id, id, contour_type, ST_AsGeoJSON(contour${magnification}) as contour, single_slide_id, single from fr_annotation
contour_type != 1
AND slide_id = #{slideId} AND single_slide_id is null
AND category_id = #{categoryId}
AND single_slide_id = #{singleSlideId}
AND slide_id in
#{item}
AND contour_type = 3
AND contour_type != 3
AND contour_type = #{contourType}
AND ST_Intersects(st_geomfromgeojson(#{contour}),contour${magnification})

select annotation_id, area, perimeter, description, category_id, location_type, annotation_type, create_by, create_time, update_by, update_time, slide_id, id, ST_AsGeoJSON(contour${magnification}) as contour, single_slide_id, contour_type, single from fr_ai_annotation_${sequenceNumber}
single_slide_id = #{singleSlideId}
AND ST_Intersects(st_geomfromgeojson(#{contour}),contour${magnification})

select annotation_id, area, perimeter, description, category_id, location_type, annotation_type, create_by, create_time, update_by, update_time, project_id, slide_id, id, ST_AsGeoJSON(contour40000) AS contour from fr_annotation
annotation_id in
#{annotationId,jdbcType=BIGINT}

SELECT count(0)
from fr_ai_annotation_${sequenceNumber}
where single_slide_id = #{singleSlideId}
  and category_id = #{categoryId}
